import React from 'react';
import './Section.css';
import Article from "../Article.js";
import { ArticleChoices } from "../ArticleChoices.js";

class Section extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
        expanded: true,
    }
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick() {
      this.setState(state => ({
          expanded: !this.state.expanded,
      }));
      this.collapse();
  }

  test(i) {
    console.log(ArticleChoices[0].stories)
    return (
        <div>
            {ArticleChoices[0].stories.map(i => (
                <p>{i}</p>
            ))}
        </div>
    )
  }

  render() {
    return (
      <div className='outer'>
          <div id='topBar'>
             <h2>{this.props.title}</h2>
          </div>
          <div className='content-holder'>
            <div id='descriptions'>
                {this.test(1)}
            </div>
            <div id='stories'>
                <Article index={1}/>
            </div>
          </div>
      </div>
    );
  }
}

const Portfolio = () => {
    return (
        <div id='portfolio'>
            <Section title='Reporting on UCLA student at the U.S. Capitol riots' index={0}/>
        </div>
    );
}

export default Portfolio;
